using ModelContextProtocol.Server;
using System.Text.Json;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        Uri = "config://app/settings",
        Name = "App Settings",
        Description = "Returns the current application configuration.",
        MimeType = "application/json")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Version = "1.0.0",
            Environment = "Production",
            Features = new
            {
                EnableLogging = true,
                MaxRetries = 3,
                TimeoutSeconds = 30
            }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        Uri = "config://app/endpoints",
        Name = "API Endpoints",
        Description = "Returns a list of available API endpoints.",
        MimeType = "application/json")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/api/users",    Methods = new[] { "GET", "POST" } },
            new { Path = "/api/products", Methods = new[] { "GET" } },
        };

        return JsonSerializer.Serialize(endpoints, JsonOptions);
    }
}

